# --- 4. 核心计算函数 ---

def haversine(lat1, lon1, lat2, lon2):
    """计算两点间距离"""
    R = 6371.0
    dlat, dlon = math.radians(lat2 - lat1), math.radians(lon2 - lon1)
    a = math.sin(dlat / 2)**2 + math.cos(math.radians(lat1)) * math.cos(math.radians(lat2)) * math.sin(dlon / 2)**2
    return R * 2 * math.atan2(math.sqrt(a), math.sqrt(1 - a))

def get_precise_distance(sub_name, mark_name):
    """
    优先使用精确坐标库计算距离。
    如果找不到，则回退到城市级别模糊计算。
    """
    # 1. 精确匹配
    sub_coord = FARM_COORDS.get(sub_name)
    mark_coord = SLAUGHTERHOUSE_COORDS.get(mark_name)
    
    if sub_coord and mark_coord:
        # 坐标库格式为 (lon, lat)，haversine 需要
        return round(haversine(sub_coord[1], sub_coord[0], mark_coord[1], mark_coord[0]), 1)
    
    # 2. 模糊匹配 (Fallback)
    def find_keyword(name):
        for city in CITY_COORDS.keys():
            if city in str(name): return city
        return None
    
    kw1, kw2 = find_keyword(sub_name), find_keyword(mark_name)
    if kw1 and kw2:
        c1, c2 = CITY_COORDS[kw1], CITY_COORDS[kw2]
        return round(haversine(c1[0], c1[1], c2[0], c2[1]), 1)
        
    return 0

def extract_weight_smart(text):
    if pd.isna(text): return "未知"
    matches = re.findall(r'(\d+)-(\d+)', str(text))
    if matches:
        valid = [(int(m[0]), int(m[1])) for m in matches if int(m[0]) > 90]
        if valid: return f"{valid[-1][0]}-{valid[-1][1]}kg"
    return "未知"

def classify_customer(name):
    if pd.isna(name): return '未知'
    if any(kw in str(name) for kw in ['公司', '有限', '集团', '合作社']): return '🏢 公户'
    return '👤 个人户'

def classify_behavior(cust_data, total_dates):
    days = cust_data['日期'].nunique()
    if len(total_dates) == 0: return "未知"
    ratio = days / len(total_dates)
    if ratio > 0.8: return "👑 忠实选手"
    if ratio < 0.2:
        if cust_data['日期'].max() == max(total_dates): return "🚀 猛然闯入选手"
        return "⚠️ 消极选手"
    return "🛡️ 稳定选手"

def process_ocr(image_file):
    try:
        img = Image.open(image_file).convert('L')
        text = pytesseract.image_to_string(img, config='--psm 6 -l chi_sim+eng')
        return text
    except: return "识别失败"

